import{_ as e,o as a,c as r,a7 as d}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"Aequor (深海)","description":"","frontmatter":{},"headers":[],"relativePath":"en/realms/aequor.md","filePath":"en/realms/aequor.md","lastUpdated":1775394001000}'),n={name:"en/realms/aequor.md"};function s(o,t,i,l,c,u){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="aequor-深海" tabindex="-1">Aequor (深海) <a class="header-anchor" href="#aequor-深海" aria-label="Permalink to &quot;Aequor (深海)&quot;">​</a></h1><p><span class="realm-badge realm-aequor">Aequor</span> is the realm of the abyssal deep sea. Aequor Awakeners specialize in summoning Tentacle entities that fight alongside them, providing sustained damage and board presence.</p><h2 id="core-identity" tabindex="-1">Core Identity <a class="header-anchor" href="#core-identity" aria-label="Permalink to &quot;Core Identity&quot;">​</a></h2><p>Aequor is a summon-based realm. Its power comes from creating Tentacle entities on the field and then empowering them to deal increasing damage over time. Currently ranked as an <strong>S-tier realm</strong> after enhancements.</p><h2 id="key-mechanics" tabindex="-1">Key Mechanics <a class="header-anchor" href="#key-mechanics" aria-label="Permalink to &quot;Key Mechanics&quot;">​</a></h2><h3 id="realm-talent-tentacle-system" tabindex="-1">Realm Talent: Tentacle System <a class="header-anchor" href="#realm-talent-tentacle-system" aria-label="Permalink to &quot;Realm Talent: Tentacle System&quot;">​</a></h3><p>At battle start, 1 Tentacle is generated. Aequor Awakeners generate additional Tentacles when playing certain cards (in addition to Aliemus). Tentacles attack the front-row enemy at the end of each turn. Each Aliemus Burst also commands Tentacles to attack once.</p><ul><li><strong>Power to Tentacle DMG ratio</strong>: 2:1</li><li><strong>Realm Mastery to extra Burst tentacle attacks</strong>: 2:1</li><li><strong>Tentacle crit rate and crit DMG</strong>: averaged across all 4 deployed Awakeners</li></ul><h3 id="pure-aequor-resonance" tabindex="-1">Pure Aequor Resonance <a class="header-anchor" href="#pure-aequor-resonance" aria-label="Permalink to &quot;Pure Aequor Resonance&quot;">​</a></h3><p>In a pure Aequor composition, the Realm Mastery stat effect is <strong>doubled</strong>, and the number of auto-generated Tentacles at battle start is also <strong>doubled</strong>.</p><h3 id="tentacle-empowerment" tabindex="-1">Tentacle Empowerment <a class="header-anchor" href="#tentacle-empowerment" aria-label="Permalink to &quot;Tentacle Empowerment&quot;">​</a></h3><p>Beyond summoning, many Aequor cards buff existing Tentacles:</p><table tabindex="0"><thead><tr><th>Effect Type</th><th>Description</th></tr></thead><tbody><tr><td>Damage Boost</td><td>Increase Tentacle attack damage</td></tr><tr><td>Additional Effects</td><td>Grant Tentacles debuffs, lifesteal, or area damage</td></tr><tr><td>Durability</td><td>Increase Tentacle HP or grant shields</td></tr><tr><td>Multiplication</td><td>Create copies of existing Tentacles</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The ideal Aequor turn involves summoning Tentacles early, then spending subsequent turns empowering them. The most obvious feature of Aequor is the automatic end-of-turn chase attack -- once you understand this, you can time your kills and cleans. Aequor is the most comfortable realm for early progression.</p></div><h2 id="aequor-awakeners" tabindex="-1">Aequor Awakeners <a class="header-anchor" href="#aequor-awakeners" aria-label="Permalink to &quot;Aequor Awakeners&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Awakener</th><th>Role</th><th>Tier</th><th>Availability</th></tr></thead><tbody><tr><td>Aurita</td><td>Attack</td><td>T2</td><td>Free (Chaos Rift I)</td></tr><tr><td>Caecus</td><td>Sub-Attack</td><td>T2</td><td>Standard</td></tr><tr><td>Celeste</td><td>Support</td><td>T1</td><td>Standard</td></tr><tr><td>Corposant</td><td>Defense</td><td>—</td><td>Limited</td></tr><tr><td>Divine King Tulu</td><td>Attack</td><td>—</td><td>Limited</td></tr><tr><td>Faros</td><td>Support</td><td>T3</td><td>Standard</td></tr><tr><td>Goliath</td><td>Defense</td><td>T1</td><td>Standard</td></tr><tr><td>Miryam</td><td>Support</td><td>—</td><td>Limited</td></tr><tr><td>Murphy</td><td>Defense</td><td>—</td><td>Standard</td></tr><tr><td>Murphy: Fauxborn</td><td>Chorus</td><td>—</td><td>Limited</td></tr><tr><td>Pickman</td><td>Attack</td><td>—</td><td>Limited</td></tr><tr><td>Shan</td><td>Sub-Attack</td><td>T1</td><td>Standard</td></tr><tr><td>Tulu</td><td>Attack</td><td>T0</td><td>Limited</td></tr></tbody></table><h2 id="team-building-with-aequor" tabindex="-1">Team Building with Aequor <a class="header-anchor" href="#team-building-with-aequor" aria-label="Permalink to &quot;Team Building with Aequor&quot;">​</a></h2><ul><li><strong>Tentacle Mixed-Damage Team</strong> -- Miryam + Aurita + Caecus + Murphy: Classic first-choice Aequor lineup, balanced offense and defense.</li><li><strong>Deep Sea Double-Carry</strong> -- Tulu + Aurita + Celeste + Shan: Faster stage clearing. Murphy can replace Shan.</li><li><strong>Caecus Counter Team</strong> -- Caecus + Hameln + Goliath + Ramona: Top-tier &quot;Caecus-Dog-Ham-Ring&quot; comp. Caecus at 3-awakening deals counter crit damage from defense cards.</li><li><strong>Shark-Caecus Team</strong> -- Goliath + Caecus + Celeste + Shan: All standard characters, great for long-term Aequor investment by beginners.</li></ul><h2 id="strengths-and-weaknesses" tabindex="-1">Strengths and Weaknesses <a class="header-anchor" href="#strengths-and-weaknesses" aria-label="Permalink to &quot;Strengths and Weaknesses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Strengths</th><th>Weaknesses</th></tr></thead><tbody><tr><td>Strong sustained damage through Tentacles</td><td>Slow ramp-up; weak first few turns</td></tr><tr><td>Free damage each turn from persistent summons</td><td>Tentacles can be destroyed by AoE enemies</td></tr><tr><td>Good board presence</td><td>Requires proper balance of summon and buff cards</td></tr><tr><td>Currently S-tier realm</td><td>—</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If all your Tentacles are destroyed, Aequor teams lose their primary damage source. Against enemies with heavy AoE, consider bringing defensive support to protect your summons.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Realms Overview</a></li><li><a href="./../cards/deckbuilding.html">Deckbuilding Guide</a></li><li><a href="./../awakeners/team-building.html">Team Building</a></li></ul>',23)])])}const p=e(n,[["render",s]]);export{m as __pageData,p as default};
